public int minTotalDistance(int[] robot, int[][] factory) {
    Arrays.sort(robot);
    Arrays.sort(factory, (a, b) -> a[0] - b[0]);

    int res = 0, idx = 0;
    for (int[] f : factory) {
        int limit = f[1];
        while (limit-- > 0 && idx < robot.length) {
            res += Math.abs(f[0] - robot[idx]);
            idx++;
        }
    }

    return res;
}
```

